class Solver3x3 {
  static Future<List<String>> resolver(EstadoCubo3x3 inicial) async {
    return await compute(_resolverIsolate, inicial.pegatinas);
  }

  static List<String> _resolverIsolate(List<int> pegatinas) {
    debugPrint("=== [SOLVER 3x3] INICIANDO ===");
    debugPrint("[SOLVER 3x3] Estado inicial (raw): $pegatinas");

    final List<int> normalizado = _normalizarOrientacion(pegatinas);
    debugPrint("[SOLVER 3x3] Estado normalizado: $normalizado");

    return _MotorIDA(Uint8List.fromList(normalizado)).resolver();
  }

  static List<int> _normalizarOrientacion(List<int> p) {
    const List<int> centros = [4, 13, 22, 31, 40, 49];
    final List<int> remap = List.filled(6, -1);
    
    for (int cara = 0; cara < 6; cara++) {
      final int colorCentro = p[centros[cara]];
      remap[colorCentro] = cara;
    }

    for (int i = 0; i < 6; i++) {
      if (remap[i] == -1) {
        debugPrint("[SOLVER 3x3] ⚠️ Normalización fallida: color $i no tiene centro asignado");
        return List<int>.from(p);
      }
    }

    debugPrint("[SOLVER 3x3] Tabla remap: $remap");
    return p.map((color) => remap[color]).toList();
  }
}

