      _cp[6]=[p0,p1,p2,p3,p4,p5,p6,p7][mc[6]]; _co[6]=([o0,o1,o2,o3,o4,o5,o6,o7][mc[6]]+mco_[6])%3;
      _cp[7]=[p0,p1,p2,p3,p4,p5,p6,p7][mc[7]]; _co[7]=([o0,o1,o2,o3,o4,o5,o6,o7][mc[7]]+mco_[7])%3;
      final e0=_ep[0],e1=_ep[1],e2=_ep[2],e3=_ep[3],e4=_ep[4],e5=_ep[5],
            e6=_ep[6],e7=_ep[7],e8=_ep[8],e9=_ep[9],e10=_ep[10],e11=_ep[11];
      final f0=_eo[0],f1=_eo[1],f2=_eo[2],f3=_eo[3],f4=_eo[4],f5=_eo[5],
            f6=_eo[6],f7=_eo[7],f8=_eo[8],f9=_eo[9],f10=_eo[10],f11=_eo[11];
      final eArr=[e0,e1,e2,e3,e4,e5,e6,e7,e8,e9,e10,e11];
      final fArr=[f0,f1,f2,f3,f4,f5,f6,f7,f8,f9,f10,f11];
      for(int i=0;i<12;i++){ _ep[i]=eArr[me[i]]; _eo[i]=(fArr[me[i]]+meo_[i])%2; }
    }
  }

  List<String> resolver(){
    if(_resuelto) return [];
    
    int lim=_h;
    while(lim<=_MAX_DEPTH){
      _pila.clear();
      if(_dfs(0,lim,-1)){
        return _pila.map((i)=>_movNombres[i]).toList();
      }
      lim++;
    }
    throw Exception("Mezcla inalcanzable. Verifica el cubo físicamente.");
  }

  bool _dfs(int g, int lim, int uc){
    if(_resuelto) return true;
    final h=_h;
    if(g+h>lim) return false;

    _save(g);

    for(int mi=0;mi<18;mi++){
      final c=_cara[mi];
      if(c==uc) continue;
      if(uc>=0 && c==_opuesta[uc] && c>uc) continue;

      _applyS(mi);
      _applyC(mi);
      _pila.add(mi);

      if(_dfs(g+1,lim,c)) return true;

      _pila.removeLast();
      _undoS(mi);
      _restore(g);
    }
    return false;
  }
}